mapper.update:
update admin_account
set last_login_at = now()
where admin_id = #{adminId}

update user_account
set enabled = #{enabled}
where user_id = #{userId}

mapper.select:
select count(1) from home_post p where 1 = 1
and ( p.title like concat('%', #{keyword}, '%') or p.description like concat('%', #{keyword}, '%') or p.publisher_name like concat('%', #{keyword}, '%') or p.tags like concat('%', #{keyword}, '%') )
and p.plaza = #{plaza}
and p.review_status = #{reviewStatus}

select p.id, p.plaza, p.publisher_user_id as publisherUserId, p.category, p.title, p.status, p.review_status as reviewStatus, p.deleted, p.publisher_name as publisherName, p.current_count as currentCount, p.max_count as maxCount, p.created_at as createdAt, p.updated_at as updatedAt from home_post p where 1 = 1
and ( p.title like concat('%', #{keyword}, '%') or p.description like concat('%', #{keyword}, '%') or p.publisher_name like concat('%', #{keyword}, '%') or p.tags like concat('%', #{keyword}, '%') )
and p.plaza = #{plaza}
and p.review_status = #{reviewStatus}
order by p.created_at desc, p.id desc limit #{size} offset #{offset}

select r.report_id as reportId, r.post_id as postId, r.reporter_user_id as reporterUserId, r.reason, r.detail, r.contact, r.status, r.created_at as createdAt, p.title as postTitle, p.plaza from home_post_report r left join home_post p on p.id = r.post_id where 1 = 1
and r.status = #{status}
order by r.created_at desc, r.report_id desc limit #{size} offset #{offset}

mapper.update:
update home_post_report
set status = #{status}
where report_id = #{reportId}

mapper.select:
select r.record_id as recordId, r.user_id as userId, p.nickname, r.school, r.student_no as studentNo, r.real_name as realName, r.identity_type as identityType, r.material_name as materialName, r.material_url as materialUrl, r.status, r.feedback, r.submitted_at as submittedAt, r.reviewed_at as reviewedAt from auth_center_record r left join user_profile p on p.user_id = r.user_id where r.auth_type = 'campus'
and r.status = #{status}
order by case r.status when 'pending' then 0 when 'passed' then 1 else 2 end, r.submitted_at desc, r.record_id desc limit #{size} offset #{offset}

mapper.update:
update user_profile
set verified = #{verified},
    verify_status = #{verifyStatus}

  , real_name = #{realName}

where user_id = #{userId}

update home_user_summary
set verified = #{verified}
where user_id = #{userId}

update admin_announcement
set title = #{title},
    content = #{content},
    status = #{status}
where announcement_id = #{announcementId}

update home_plaza_category
set plaza_key = #{plazaKey},
    category_name = #{categoryName},
    sort_weight = #{sortWeight}
where id = #{categoryId}

update home_plaza_category
set enabled = #{enabled}
where id = #{categoryId}
